# -*- coding: utf-8 -*-
"""
Migration 18.0.1.1.0 — Fix web_icon_data per tutti i moduli CasaFolino.

Odoo scrive web_icon_data nel DB solo alla prima installazione e non
aggiorna automaticamente il campo al successivo -u anche se il file
PNG su disco è cambiato. Questa migration inietta i PNG corretti
(base64, solid-color 128x128) direttamente in ir_module_module.
"""
import logging
_logger = logging.getLogger(__name__)

# PNG 128x128 solid-color (base64) generati con Python puro
ICONS = {
    'casafolino_allergen': '',
    'casafolino_nutrition': '',
    'casafolino_recall': '',
    'casafolino_supplier_qual': '',
    'casafolino_gdo': '',
    'casafolino_private_label': '',
    'casafolino_production': '',
    'casafolino_kpi': '',
    'casafolino_treasury': '',
    'casafolino_home': '',
    'casafolino_haccp': '',
    'casafolino_mail': '',
    'casafolino_crm_export': '',
}


def migrate(cr, version):
    for module_name, b64_data in ICONS.items():
        cr.execute(
            "UPDATE ir_module_module SET web_icon_data = %s "
            "WHERE name = %s",
            (b64_data, module_name),
        )
        if cr.rowcount:
            _logger.info("fix_icons: aggiornata icona per %s", module_name)
        else:
            _logger.debug("fix_icons: modulo %s non trovato nel DB (non installato)", module_name)
